import axios from 'axios';

const API_BASE = process.env.REACT_APP_API_URL || '/api';

const api = axios.create({
  baseURL: API_BASE,
  headers: { 'Content-Type': 'application/json' }
});

// Attach token
api.interceptors.request.use(config => {
  const token = localStorage.getItem('token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

// Handle auth errors — but DON'T redirect during initial /me check
// Only redirect if we have a user session that expired mid-use
api.interceptors.response.use(
  res => res,
  err => {
    if (err.response?.status === 401) {
      const isAuthCheck = err.config?.url?.includes('/auth/me');
      if (!isAuthCheck) {
        // Soft redirect: clear storage and dispatch event.
        // AuthContext listens for this and calls logout() + navigates via React Router,
        // which preserves SPA state instead of a hard window.location reload.
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        window.dispatchEvent(new Event('auth:logout'));
      }
    }
    return Promise.reject(err);
  }
);

export const authAPI = {
  login: (data) => api.post('/auth/login', data),
  me: () => api.get('/auth/me'),
  changePassword: (data) => api.put('/auth/change-password', data)
};

export const guardsAPI = {
  getAll: () => api.get('/guards'),
  create: (data) => api.post('/guards', data),
  update: (id, data) => api.put(`/guards/${id}`, data),
  delete: (id) => api.delete(`/guards/${id}`)
};

export const attendanceAPI = {
  checkIn: (data) => api.post('/attendance/checkin', data),
  checkOut: (data) => api.post('/attendance/checkout', data),
  getMyAttendance: (params) => api.get('/attendance/my', { params }),
  getToday: () => api.get('/attendance/today'),
  getAllAttendance: (params) => api.get('/attendance/all', { params }),
  getGuardAttendance: (id, params) => api.get(`/attendance/guard/${id}`, { params })
};

export const dashboardAPI = {
  getStats: () => api.get('/dashboard/stats'),
  getLive: () => api.get('/dashboard/live')
};

export default api;
